9697   // - The predicate is monotonic in the iteration space.
9698   // - If the check does not fail on the 1st iteration:
9699   //   - No overflow will happen during first MaxIter iterations;
9700   //   - It will not fail on the MaxIter'th iteration.
9701   // If the check does fail on the 1st iteration, we leave the loop and no
9702   // other checks matter.
9703 
9704   // If there is a loop-invariant, force it into the RHS, otherwise bail out.
9705   if (!isLoopInvariant(RHS, L)) {
9706     if (!isLoopInvariant(LHS, L))
9707       return None;
9708 
9709     std::swap(LHS, RHS);
9710     Pred = ICmpInst::getSwappedPredicate(Pred);
9711   }
9712 
9713   auto *AR = dyn_cast<SCEVAddRecExpr>(LHS);
9714   if (!AR || AR->getLoop() != L)
9715     return None;
9716 
9717   // The predicate must be relational (i.e. <, <=, >=, >).
9718   if (!ICmpInst::isRelational(Pred))
9719     return None;
9720 
9721   // TODO: Support steps other than +/- 1.
9722   const SCEV *Step = AR->getStepRecurrence(*this);
