9631       return None;
9632 
9633     const SCEV *Step = LHS->getStepRecurrence(*this);
9634 
9635     if (isKnownNonNegative(Step))
9636       return IsGreater ? MonotonicallyIncreasing : MonotonicallyDecreasing;
9637 
9638     if (isKnownNonPositive(Step))
9639       return !IsGreater ? MonotonicallyIncreasing : MonotonicallyDecreasing;
9640 
9641     return None;
9642   }
9643 }
