9645 Optional<ScalarEvolution::LoopInvariantPredicate>
9646 ScalarEvolution::getLoopInvariantPredicate(ICmpInst::Predicate Pred,
9647                                            const SCEV *LHS, const SCEV *RHS,
9648                                            const Loop *L) {
9649 
9650   // If there is a loop-invariant, force it into the RHS, otherwise bail out.
9651   if (!isLoopInvariant(RHS, L)) {
9652     if (!isLoopInvariant(LHS, L))
9653       return None;
9654 
9655     std::swap(LHS, RHS);
9656     Pred = ICmpInst::getSwappedPredicate(Pred);
9657   }
9658 
9659   const SCEVAddRecExpr *ArLHS = dyn_cast<SCEVAddRecExpr>(LHS);
9660   if (!ArLHS || ArLHS->getLoop() != L)
9661     return None;
9662 
9663   auto MonotonicType = getMonotonicPredicateType(ArLHS, Pred);
9664   if (!MonotonicType)
9665     return None;
9666   // If the predicate "ArLHS `Pred` RHS" monotonically increases from false to
9667   // true as the loop iterates, and the backedge is control dependent on
9668   // "ArLHS `Pred` RHS" == true then we can reason as follows:
9669   //
9670   //   * if the predicate was false in the first iteration then the predicate
9671   //     is never evaluated again, since the loop exits without taking the
9672   //     backedge.
9673   //   * if the predicate was true in the first iteration then it will
9674   //     continue to be true for all future iterations since it is
9675   //     monotonically increasing.
9676   //
9677   // For both the above possibilities, we can replace the loop varying
9678   // predicate with its value on the first iteration of the loop (which is
9679   // loop invariant).
9680   //
9681   // A similar reasoning applies for a monotonically decreasing predicate, by
9682   // replacing true with false and false with true in the above two bullets.
9683   bool Increasing = *MonotonicType == ScalarEvolution::MonotonicallyIncreasing;
9684   auto P = Increasing ? Pred : ICmpInst::getInversePredicate(Pred);
9685 
9686   if (!isLoopBackedgeGuardedByCond(L, P, LHS, RHS))
9687     return None;
9688 
9689   return ScalarEvolution::LoopInvariantPredicate(Pred, ArLHS->getStart(), RHS);
9690 }
9691 
9692 Optional<ScalarEvolution::LoopInvariantPredicate>
9693 ScalarEvolution::getLoopInvariantExitCondDuringFirstIterations(
9694     ICmpInst::Predicate Pred, const SCEV *LHS, const SCEV *RHS, const Loop *L,
9695     const Instruction *Context, const SCEV *MaxIter) {
9696   // Try to prove the following set of facts:
9697   // - The predicate is monotonic in the iteration space.
9698   // - If the check does not fail on the 1st iteration:
9699   //   - No overflow will happen during first MaxIter iterations;
9700   //   - It will not fail on the MaxIter'th iteration.
9701   // If the check does fail on the 1st iteration, we leave the loop and no
9702   // other checks matter.
9703 
9704   // If there is a loop-invariant, force it into the RHS, otherwise bail out.
9705   if (!isLoopInvariant(RHS, L)) {
9706     if (!isLoopInvariant(LHS, L))
9707       return None;
9708 
9709     std::swap(LHS, RHS);
9710     Pred = ICmpInst::getSwappedPredicate(Pred);
9711   }
9712 
9713   auto *AR = dyn_cast<SCEVAddRecExpr>(LHS);
9714   if (!AR || AR->getLoop() != L)
9715     return None;
9716 
9717   // The predicate must be relational (i.e. <, <=, >=, >).
9718   if (!ICmpInst::isRelational(Pred))
9719     return None;
9720 
9721   // TODO: Support steps other than +/- 1.
9722   const SCEV *Step = AR->getStepRecurrence(*this);
9723   auto *One = getOne(Step->getType());
9724   auto *MinusOne = getNegativeSCEV(One);
9725   if (Step != One && Step != MinusOne)
9726     return None;
9727 
9728   // Type mismatch here means that MaxIter is potentially larger than max
9729   // unsigned value in start type, which mean we cannot prove no wrap for the
9730   // indvar.
9731   if (AR->getType() != MaxIter->getType())
9732     return None;
9733 
9734   // Value of IV on suggested last iteration.
9735   const SCEV *Last = AR->evaluateAtIteration(MaxIter, *this);
9736   // Does it still meet the requirement?
9737   if (!isLoopBackedgeGuardedByCond(L, Pred, Last, RHS))
9738     return None;
9739   // Because step is +/- 1 and MaxIter has same type as Start (i.e. it does
9740   // not exceed max unsigned value of this type), this effectively proves
9741   // that there is no wrap during the iteration. To prove that there is no
9742   // signed/unsigned wrap, we need to check that
9743   // Start <= Last for step = 1 or Start >= Last for step = -1.
9744   ICmpInst::Predicate NoOverflowPred =
9745       CmpInst::isSigned(Pred) ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
9746   if (Step == MinusOne)
9747     NoOverflowPred = CmpInst::getSwappedPredicate(NoOverflowPred);
9748   const SCEV *Start = AR->getStart();
9749   if (!isKnownPredicateAt(NoOverflowPred, Start, Last, Context))
9750     return None;
9751 
9752   // Everything is fine.
9753   return ScalarEvolution::LoopInvariantPredicate(Pred, Start, RHS);
9754 }
9755 
9756 bool ScalarEvolution::isKnownPredicateViaConstantRanges(
9757     ICmpInst::Predicate Pred, const SCEV *LHS, const SCEV *RHS) {
9758   if (HasSameValue(LHS, RHS))
9759     return ICmpInst::isTrueWhenEqual(Pred);
9760 
9761   // This code is split out from isKnownPredicate because it is called from
9762   // within isLoopEntryGuardedByCond.
9763 
9764   auto CheckRanges =
9765       [&](const ConstantRange &RangeLHS, const ConstantRange &RangeRHS) {
9766     return ConstantRange::makeSatisfyingICmpRegion(Pred, RangeRHS)
9767         .contains(RangeLHS);
9768   };
9769 
9770   // The check at the top of the function catches the case where the values are
9771   // known to be equal.
9772   if (Pred == CmpInst::ICMP_EQ)
9773     return false;
9774 
9775   if (Pred == CmpInst::ICMP_NE)
9776     return CheckRanges(getSignedRange(LHS), getSignedRange(RHS)) ||
9777            CheckRanges(getUnsignedRange(LHS), getUnsignedRange(RHS)) ||
9778            isKnownNonZero(getMinusSCEV(LHS, RHS));
9779 
9780   if (CmpInst::isSigned(Pred))
9781     return CheckRanges(getSignedRange(LHS), getSignedRange(RHS));
9782 
9783   return CheckRanges(getUnsignedRange(LHS), getUnsignedRange(RHS));
9784 }
